// Expanded Seed Contacts — curated music industry contacts
// All emails use organizational/role-based patterns (submissions@, music@, etc.)
// sourced from publicly listed contact pages.
// ══════════════════════════════════════════════════════════════════════════════

export interface SeedContact {
  id: string;
  name: string;
  email: string;
  outlet: string;
  type: "radio" | "journalist" | "curator" | "podcaster" | "blog";
  genre: string;
  region: string;
  beat: string;
  bio: string;
  website: string;
  verified: false;
  articleCount: 0;
}

// Helper to generate a consistent id from email
function cid(email: string): string {
  return `seed-${email.replace(/[@.]/g, "-")}`;
}

